import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    best_node = None
    min_combined_time = np.inf

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = np.linalg.norm(cur_truck_pos - customer_pos)
        wait_time = 0

        for other_truck_pos in all_truck_pos:
            if other_truck_pos is not cur_truck_pos:
                other_travel_time = np.linalg.norm(other_truck_pos - customer_pos)
                if other_travel_time < travel_time:
                    wait_time = max(wait_time, travel_time - other_travel_time)

        combined_time = travel_time + wait_time

        if combined_time < min_combined_time:
            min_combined_time = combined_time
            best_node = i

    return best_node

