import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    penalty = 0.05  # Penalty for distance from truck position
    bonus = 0.05  # Bonus for proximity to other trucks
    best_score = float('inf')
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        dist_from_truck = np.linalg.norm(cur_truck_pos - customer_pos)
        dist_from_depot = np.linalg.norm(depot_pos - customer_pos)

        min_dist_from_other_trucks = float('inf')
        for truck_pos in all_truck_pos:
            if truck_pos is not cur_truck_pos:
                dist = np.linalg.norm(truck_pos - customer_pos)
                if dist < min_dist_from_other_trucks:
                    min_dist_from_other_trucks = dist

        total_score = dist_from_truck + dist_from_depot * penalty - min_dist_from_other_trucks * bonus

        if total_score < best_score:
            best_score = total_score
            best_node = i

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    min_total_distance = float('inf')
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        for truck_pos in all_truck_pos:
            total_distance = np.linalg.norm(cur_truck_pos - customer_pos) + np.linalg.norm(truck_pos - customer_pos)
            if total_distance < min_total_distance:
                min_total_distance = total_distance
                best_node = i

    return best_node
